solution_code:
#include <chrono>
#include <iostream>

int main()
{
    long long startVal{};
    long long endVal{};
    std::cin >> startVal >> endVal;

    std::chrono::milliseconds startMs{ startVal };
    std::chrono::milliseconds endMs{ endVal };
    auto elapsed{ endMs - startMs };

    std::chrono::microseconds elapsedUs{ elapsed };
    auto elapsedS{ std::chrono::duration_cast<std::chrono::seconds>(elapsed) };

    std::cout << "Elapsed: " << elapsed.count() << " ms" << '\n';
    std::cout << "Elapsed: " << elapsedUs.count() << " us" << '\n';
    std::cout << "Elapsed: " << elapsedS.count() << " s" << '\n';

    return 0;
}
